/**
 * ROM → WASM Code Generator.
 *
 * Generates self-contained C source code from a trained ROM (MLP, RBF,
 * or polynomial) that compiles to WebAssembly via Emscripten. The
 * generated code embeds all trained weights as static arrays and
 * implements:
 *
 *   - `rom_evaluate()`: Forward-pass inference
 *   - FMI2 co-simulation wrappers (`wasm_do_step`, `wasm_get_var`, etc.)
 *
 * The output is a drop-in replacement for the physics-based WASM code
 * generated by {@link generateFmuWasmSource} — same ABI, orders of
 * magnitude faster.
 */

import type { ROMWeights, ScalingParams, TrainedROM } from "@modelscript/compiler/simulator";

// ─────────────────────────────────────────────────────────────────────
// Public Interface
// ─────────────────────────────────────────────────────────────────────

/** Result of ROM WASM C source generation. */
export interface RomWasmSourceResult {
  /** The single C source file for Emscripten compilation. */
  wasmC: string;
  /** Recommended `emcc` command-line flags. */
  emccFlags: string[];
  /** List of exported WASM function names. */
  exportedFunctions: string[];
  /** Generated modelDescription.xml for FMU packaging. */
  modelDescriptionXml: string;
}

/**
 * Generate a self-contained C source file from a trained ROM,
 * targeting Emscripten/WASM. The result is a fast surrogate FMU
 * that evaluates the ROM forward pass instead of solving ODEs.
 *
 * @param rom              The trained ROM (from `trainROM`)
 * @param modelIdentifier  Model name for code generation
 * @returns WASM source artifacts ready for compilation
 */
export function generateRomWasmSource(rom: TrainedROM, modelIdentifier: string): RomWasmSourceResult {
  const nInputs = rom.inputNames.length;
  const nOutputs = rom.outputNames.length;
  const nVars = nInputs + nOutputs;

  const exportedFunctions = [
    "_wasm_init",
    "_wasm_do_step",
    "_wasm_get_n_inputs",
    "_wasm_get_n_outputs",
    "_wasm_get_n_vars",
    "_wasm_set_input",
    "_wasm_get_output",
    "_wasm_get_var",
    "_wasm_set_var",
    "_wasm_get_time",
    "_wasm_get_metrics",
    "_malloc",
    "_free",
  ];

  const emccFlags = [
    "-O2",
    "-sWASM=1",
    "-sMODULARIZE=1",
    `-sEXPORT_NAME="createRomModel"`,
    `-sEXPORTED_FUNCTIONS="[${exportedFunctions.map((f) => `'${f}'`).join(",")}]"`,
    `-sEXPORTED_RUNTIME_METHODS="['ccall','cwrap','getValue','setValue']"`,
    "-sALLOW_MEMORY_GROWTH=1",
    "-lm",
  ];

  const wasmC = generateRomC(rom, modelIdentifier, nInputs, nOutputs, nVars);
  const modelDescriptionXml = generateRomModelDescription(rom, modelIdentifier);

  return { wasmC, emccFlags, exportedFunctions, modelDescriptionXml };
}

// ─────────────────────────────────────────────────────────────────────
// C Source Generator
// ─────────────────────────────────────────────────────────────────────

function formatDouble(v: number): string {
  if (!isFinite(v)) {
    if (v === Infinity) return "INFINITY";
    if (v === -Infinity) return "(-INFINITY)";
    return "NAN";
  }
  const s = v.toString();
  if (!s.includes(".") && !s.includes("e") && !s.includes("E")) return s + ".0";
  return s;
}

function emitArray1D(name: string, values: number[]): string {
  const vals = values.map(formatDouble).join(", ");
  return `static const double ${name}[${values.length}] = {${vals}};`;
}

function emitArray2D(name: string, matrix: number[][]): string {
  const rows = matrix.length;
  const cols = matrix[0]?.length ?? 0;
  const lines: string[] = [];
  lines.push(`static const double ${name}[${rows}][${cols}] = {`);
  for (let i = 0; i < rows; i++) {
    const row = matrix[i]!;
    const vals = row.map(formatDouble).join(", ");
    lines.push(`  {${vals}}${i < rows - 1 ? "," : ""}`);
  }
  lines.push("};");
  return lines.join("\n");
}

function emitScalingArrays(prefix: string, scaling: ScalingParams[]): string {
  const means = scaling.map((s) => s.mean);
  const stds = scaling.map((s) => s.std);
  return [emitArray1D(`${prefix}_mean`, means), emitArray1D(`${prefix}_std`, stds)].join("\n");
}

function generateRomC(rom: TrainedROM, id: string, nInputs: number, nOutputs: number, nVars: number): string {
  const L: string[] = [];

  // ── Header ──
  L.push(`/* Auto-generated by ModelScript ROM Codegen — ${id} */`);
  L.push("/* Surrogate model: trained ROM compiled to WebAssembly */");
  L.push(`/* Architecture: ${rom.architecture} */`);
  L.push(`/* Training R²: ${rom.metrics.r2.toFixed(6)} */`);
  L.push("");
  L.push("#include <math.h>");
  L.push("#include <string.h>");
  L.push("");
  L.push("#ifdef __EMSCRIPTEN__");
  L.push("#include <emscripten/emscripten.h>");
  L.push("#else");
  L.push("#define EMSCRIPTEN_KEEPALIVE");
  L.push("#endif");
  L.push("");

  // ── Constants ──
  L.push(`#define N_INPUTS  ${nInputs}`);
  L.push(`#define N_OUTPUTS ${nOutputs}`);
  L.push(`#define N_VARS    ${nVars}`);
  L.push("");

  // ── Global state ──
  L.push("/* Global model state */");
  L.push("static double g_inputs[N_INPUTS];");
  L.push("static double g_outputs[N_OUTPUTS];");
  L.push("static double g_time = 0.0;");
  L.push("");

  // ── Normalization parameters ──
  L.push("/* Normalization parameters */");
  L.push(emitScalingArrays("in", rom.inputScaling));
  L.push(emitScalingArrays("out", rom.outputScaling));
  L.push("");

  // ── Embedded weights ──
  L.push("/* Trained weights */");
  L.push(emitWeights(rom.weights));
  L.push("");

  // ── Forward pass ──
  L.push("/* Forward pass: evaluate ROM */");
  L.push("static void rom_evaluate(const double* inputs, double* outputs) {");
  L.push(emitForwardPass(rom));
  L.push("}");
  L.push("");

  // ── Exported API ──
  L.push("/* ═══════════════════════════════════════════════════════ */");
  L.push("/*  Exported WASM API                                     */");
  L.push("/* ═══════════════════════════════════════════════════════ */");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("void wasm_init(void) {");
  L.push("  memset(g_inputs, 0, sizeof(g_inputs));");
  L.push("  memset(g_outputs, 0, sizeof(g_outputs));");
  L.push("  g_time = 0.0;");
  L.push("}");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("void wasm_do_step(double t, double dt) {");
  L.push("  g_time = t + dt;");
  L.push("  rom_evaluate(g_inputs, g_outputs);");
  L.push("}");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("int wasm_get_n_inputs(void) { return N_INPUTS; }");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("int wasm_get_n_outputs(void) { return N_OUTPUTS; }");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("int wasm_get_n_vars(void) { return N_VARS; }");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("void wasm_set_input(int idx, double value) {");
  L.push("  if (idx >= 0 && idx < N_INPUTS) g_inputs[idx] = value;");
  L.push("}");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("double wasm_get_output(int idx) {");
  L.push("  if (idx >= 0 && idx < N_OUTPUTS) return g_outputs[idx];");
  L.push("  return 0.0;");
  L.push("}");
  L.push("");

  // Generic get/set by value reference (inputs first, then outputs)
  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("void wasm_set_var(int vr, double value) {");
  L.push("  if (vr >= 0 && vr < N_INPUTS) g_inputs[vr] = value;");
  L.push("}");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("double wasm_get_var(int vr) {");
  L.push("  if (vr >= 0 && vr < N_INPUTS) return g_inputs[vr];");
  L.push("  if (vr >= N_INPUTS && vr < N_VARS) return g_outputs[vr - N_INPUTS];");
  L.push("  return 0.0;");
  L.push("}");
  L.push("");

  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("double wasm_get_time(void) { return g_time; }");
  L.push("");

  // Metrics accessor (R², train MSE, val MSE)
  L.push("EMSCRIPTEN_KEEPALIVE");
  L.push("double wasm_get_metrics(int idx) {");
  L.push(`  if (idx == 0) return ${formatDouble(rom.metrics.r2)};`);
  L.push(`  if (idx == 1) return ${formatDouble(rom.metrics.trainMSE)};`);
  L.push(`  if (idx == 2) return ${formatDouble(rom.metrics.valMSE)};`);
  L.push("  return 0.0;");
  L.push("}");
  L.push("");

  return L.join("\n");
}

// ─────────────────────────────────────────────────────────────────────
// Architecture-Specific Weight Emission
// ─────────────────────────────────────────────────────────────────────

function emitWeights(weights: ROMWeights): string {
  switch (weights.type) {
    case "mlp":
      return emitMLPWeights(weights);
    case "polynomial":
      return emitPolynomialWeights(weights);
    case "rbf":
      return emitRBFWeights(weights);
  }
}

function emitMLPWeights(w: Extract<ROMWeights, { type: "mlp" }>): string {
  const lines: string[] = [];
  lines.push(`#define N_LAYERS ${w.layers.length}`);
  for (let l = 0; l < w.layers.length; l++) {
    const layer = w.layers[l]!;
    lines.push(emitArray2D(`W${l}`, layer.W));
    lines.push(emitArray1D(`b${l}`, layer.b));
  }
  // Emit layer size array for the generic forward-pass loop
  const sizes = w.layers.map((l) => l.W.length);
  lines.push(emitArray1D("layer_sizes", sizes));
  return lines.join("\n");
}

function emitPolynomialWeights(w: Extract<ROMWeights, { type: "polynomial" }>): string {
  const lines: string[] = [];
  lines.push(`#define POLY_DEGREE ${w.degree}`);
  lines.push(`#define POLY_N_INPUTS ${w.nInputs}`);
  // Emit coefficient matrix: [nOutputs][nBasis]
  lines.push(emitArray2D("poly_coefficients", w.coefficients));
  lines.push(`#define POLY_N_BASIS ${w.coefficients[0]?.length ?? 0}`);
  return lines.join("\n");
}

function emitRBFWeights(w: Extract<ROMWeights, { type: "rbf" }>): string {
  const lines: string[] = [];
  lines.push(`#define RBF_N_CENTERS ${w.centers.length}`);
  lines.push(`#define RBF_EPSILON ${formatDouble(w.epsilon)}`);
  lines.push(emitArray2D("rbf_centers", w.centers));
  lines.push(emitArray2D("rbf_weights", w.weights));
  return lines.join("\n");
}

// ─────────────────────────────────────────────────────────────────────
// Architecture-Specific Forward Pass Emission
// ─────────────────────────────────────────────────────────────────────

function emitForwardPass(rom: TrainedROM): string {
  switch (rom.weights.type) {
    case "mlp":
      return emitMLPForwardPass(rom.weights);
    case "polynomial":
      return emitPolynomialForwardPass(rom.weights);
    case "rbf":
      return emitRBFForwardPass(rom.weights);
  }
}

function emitMLPForwardPass(w: Extract<ROMWeights, { type: "mlp" }>): string {
  const lines: string[] = [];
  const nLayers = w.layers.length;
  const maxNeurons = Math.max(...w.layers.map((l) => Math.max(l.W.length, l.W[0]?.length ?? 0)));

  lines.push(`  double a[${maxNeurons}], b[${maxNeurons}];`);
  lines.push(`  double normed[N_INPUTS];`);
  lines.push("");

  // Normalize inputs
  lines.push("  /* Normalize inputs */");
  lines.push("  for (int i = 0; i < N_INPUTS; i++)");
  lines.push("    normed[i] = (inputs[i] - in_mean[i]) / in_std[i];");
  lines.push("");

  // Unrolled layer evaluation
  for (let l = 0; l < nLayers; l++) {
    const layer = w.layers[l]!;
    const nOut = layer.W.length;
    const nIn = layer.W[0]?.length ?? 0;
    const inputVar = l === 0 ? "normed" : l % 2 === 1 ? "a" : "b";
    const outputVar = l === nLayers - 1 ? "b" : l % 2 === 0 ? "a" : "b";
    const isOutput = l === nLayers - 1;
    const activationName = w.activation === "relu" ? "relu" : w.activation === "sigmoid" ? "sigmoid" : "tanh";

    lines.push(`  /* Layer ${l}: ${nIn} → ${nOut}${isOutput ? " (linear output)" : ` (${activationName})`} */`);
    lines.push(`  for (int i = 0; i < ${nOut}; i++) {`);
    lines.push(`    double z = b${l}[i];`);
    lines.push(`    for (int j = 0; j < ${nIn}; j++) z += W${l}[i][j] * ${inputVar}[j];`);

    if (isOutput) {
      lines.push(`    ${outputVar}[i] = z;`);
    } else {
      switch (w.activation) {
        case "relu":
          lines.push(`    ${outputVar}[i] = z > 0.0 ? z : 0.0;`);
          break;
        case "sigmoid":
          lines.push(`    ${outputVar}[i] = 1.0 / (1.0 + exp(-z));`);
          break;
        default:
          lines.push(`    ${outputVar}[i] = tanh(z);`);
          break;
      }
    }
    lines.push("  }");
    lines.push("");
  }

  // Denormalize outputs
  const finalVar = nLayers % 2 === 0 ? "b" : "a";
  lines.push("  /* Denormalize outputs */");
  lines.push("  for (int i = 0; i < N_OUTPUTS; i++)");
  lines.push(`    outputs[i] = ${nLayers === 1 ? "b" : finalVar}[i] * out_std[i] + out_mean[i];`);

  return lines.join("\n");
}

function emitPolynomialForwardPass(w: Extract<ROMWeights, { type: "polynomial" }>): string {
  const lines: string[] = [];
  const nBasis = w.coefficients[0]?.length ?? 0;
  const nOutputs = w.coefficients.length;

  lines.push("  double normed[N_INPUTS];");
  lines.push("");
  lines.push("  /* Normalize inputs */");
  lines.push("  for (int i = 0; i < N_INPUTS; i++)");
  lines.push("    normed[i] = (inputs[i] - in_mean[i]) / in_std[i];");
  lines.push("");

  // Generate monomial basis evaluation
  // We regenerate the same monomials that trainPolynomial used
  const monomials = generateMonomials(w.nInputs, w.degree);

  lines.push(`  double basis[${nBasis}];`);
  for (let m = 0; m < monomials.length; m++) {
    const mono = monomials[m]!;
    const terms: string[] = [];
    for (let i = 0; i < mono.length; i++) {
      const power = mono[i]!;
      if (power === 1) terms.push(`normed[${i}]`);
      else if (power === 2) terms.push(`(normed[${i}] * normed[${i}])`);
      else if (power > 2) terms.push(`pow(normed[${i}], ${power}.0)`);
    }
    if (terms.length === 0) {
      lines.push(`  basis[${m}] = 1.0;`);
    } else {
      lines.push(`  basis[${m}] = ${terms.join(" * ")};`);
    }
  }
  lines.push("");

  // Evaluate polynomial for each output
  lines.push(`  /* Evaluate polynomial (${nOutputs} outputs, ${nBasis} basis functions) */`);
  lines.push(`  for (int o = 0; o < ${nOutputs}; o++) {`);
  lines.push("    double sum = 0.0;");
  lines.push(`    for (int b = 0; b < ${nBasis}; b++)`);
  lines.push("      sum += poly_coefficients[o][b] * basis[b];");
  lines.push("    outputs[o] = sum * out_std[o] + out_mean[o];");
  lines.push("  }");

  return lines.join("\n");
}

function emitRBFForwardPass(w: Extract<ROMWeights, { type: "rbf" }>): string {
  const lines: string[] = [];
  const nCenters = w.centers.length;
  const nOutputs = w.weights.length;

  lines.push("  double normed[N_INPUTS];");
  lines.push(`  double phi[${nCenters}];`);
  lines.push("");
  lines.push("  /* Normalize inputs */");
  lines.push("  for (int i = 0; i < N_INPUTS; i++)");
  lines.push("    normed[i] = (inputs[i] - in_mean[i]) / in_std[i];");
  lines.push("");

  // Compute kernel values
  lines.push("  /* Compute Gaussian RBF kernel values */");
  lines.push(`  for (int j = 0; j < ${nCenters}; j++) {`);
  lines.push("    double r2 = 0.0;");
  lines.push("    for (int k = 0; k < N_INPUTS; k++) {");
  lines.push("      double d = normed[k] - rbf_centers[j][k];");
  lines.push("      r2 += d * d;");
  lines.push("    }");
  lines.push(`    phi[j] = exp(-r2 / (2.0 * RBF_EPSILON * RBF_EPSILON));`);
  lines.push("  }");
  lines.push("");

  // Weighted sum
  lines.push(`  /* Weighted sum (${nOutputs} outputs) */`);
  lines.push(`  for (int o = 0; o < ${nOutputs}; o++) {`);
  lines.push("    double sum = 0.0;");
  lines.push(`    for (int j = 0; j < ${nCenters}; j++)`);
  lines.push("      sum += rbf_weights[o][j] * phi[j];");
  lines.push("    outputs[o] = sum * out_std[o] + out_mean[o];");
  lines.push("  }");

  return lines.join("\n");
}

// ─────────────────────────────────────────────────────────────────────
// Monomial Generation (mirrors rom-trainer.ts)
// ─────────────────────────────────────────────────────────────────────

function generateMonomials(nInputs: number, degree: number): number[][] {
  const monomials: number[][] = [];
  function enumerate(d: number, startIdx: number, current: number[]): void {
    monomials.push([...current]);
    if (d === 0) return;
    for (let i = startIdx; i < nInputs; i++) {
      current[i]!++;
      enumerate(d - 1, i, current);
      current[i]!--;
    }
  }
  enumerate(degree, 0, new Array(nInputs).fill(0));
  return monomials;
}

// ─────────────────────────────────────────────────────────────────────
// modelDescription.xml for ROM FMU
// ─────────────────────────────────────────────────────────────────────

function escapeXml(s: string): string {
  return s.replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;").replace(/"/g, "&quot;");
}

function generateRomModelDescription(rom: TrainedROM, modelIdentifier: string): string {
  const lines: string[] = [];
  const guid = `{rom-${Date.now().toString(16)}}`;

  lines.push('<?xml version="1.0" encoding="UTF-8"?>');
  lines.push("<fmiModelDescription");
  lines.push('  fmiVersion="2.0"');
  lines.push(`  modelName="${escapeXml(modelIdentifier)}"`);
  lines.push(`  guid="${guid}"`);
  lines.push(`  description="Surrogate ROM (${rom.architecture}, R²=${rom.metrics.r2.toFixed(4)})"`);
  lines.push('  generationTool="ModelScript ROM Codegen"');
  lines.push(`  generationDateAndTime="${new Date().toISOString()}"`);
  lines.push('  variableNamingConvention="structured"');
  lines.push('  numberOfEventIndicators="0">');
  lines.push("");

  lines.push(
    `  <CoSimulation modelIdentifier="${escapeXml(modelIdentifier)}" canHandleVariableCommunicationStepSize="true" />`,
  );
  lines.push("");

  lines.push('  <DefaultExperiment startTime="0" stopTime="1" stepSize="0.001" />');
  lines.push("");

  // Variables
  lines.push("  <ModelVariables>");

  let vr = 0;

  // Inputs
  for (const name of rom.inputNames) {
    lines.push(
      `    <ScalarVariable name="${escapeXml(name)}" valueReference="${vr}" causality="input" variability="continuous">`,
    );
    lines.push('      <Real start="0" />');
    lines.push("    </ScalarVariable>");
    vr++;
  }

  // Outputs
  for (const name of rom.outputNames) {
    lines.push(
      `    <ScalarVariable name="${escapeXml(name)}" valueReference="${vr}" causality="output" variability="continuous" initial="calculated">`,
    );
    lines.push("      <Real />");
    lines.push("    </ScalarVariable>");
    vr++;
  }

  lines.push("  </ModelVariables>");
  lines.push("");

  // Model structure
  lines.push("  <ModelStructure>");
  lines.push("    <Outputs>");
  for (let i = 0; i < rom.outputNames.length; i++) {
    const idx = rom.inputNames.length + i + 1; // 1-based index
    // Each output depends on all inputs
    const deps = rom.inputNames.map((_, j) => j + 1).join(" ");
    lines.push(`      <Unknown index="${idx}" dependencies="${deps}" />`);
  }
  lines.push("    </Outputs>");
  lines.push("  </ModelStructure>");
  lines.push("");
  lines.push("</fmiModelDescription>");

  return lines.join("\n");
}
